import{_ as e,o as a,c as s,ae as t}from"./chunks/framework.BGHOrOyn.js";const k=JSON.parse('{"title":"Dockerizing an existing ROS project","description":"","frontmatter":{},"headers":[],"relativePath":"robotics/ros/dockerizing-an-existing-ros-project.md","filePath":"robotics/ros/dockerizing-an-existing-ros-project.md"}'),n={name:"robotics/ros/dockerizing-an-existing-ros-project.md"};function o(r,i,h,d,l,p){return a(),s("div",null,[...i[0]||(i[0]=[t('<h1 id="dockerizing-an-existing-ros-project" tabindex="-1">Dockerizing an existing ROS project <a class="header-anchor" href="#dockerizing-an-existing-ros-project" aria-label="Permalink to &quot;Dockerizing an existing ROS project&quot;">​</a></h1><p><a href="https://github.com/tkunic/ros-docker-simple" target="_blank" rel="noreferrer">https://github.com/tkunic/ros-docker-simple</a></p><h2 id="ros-docker-simple" tabindex="-1">ROS Docker Simple <a class="header-anchor" href="#ros-docker-simple" aria-label="Permalink to &quot;ROS Docker Simple&quot;">​</a></h2><p>A simple template project for <a href="https://www.docker.com/" target="_blank" rel="noreferrer">dockerizing</a> your <a href="http://www.ros.org/" target="_blank" rel="noreferrer">ROS</a> code. Have your ROS project set up and running in 3 minutes by putting your catkin workspace in <code>catkin_ws</code> and running:</p><p><code>cp ros-project</code></p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> apt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">get</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> docker</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">script</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">build</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">script</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">run</span></span></code></pre></div><p>And that&#39;s it!</p><h3 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h3><h4 id="how-can-i-use-a-different-version-of-ros" tabindex="-1">How can I use a different version of ROS? <a class="header-anchor" href="#how-can-i-use-a-different-version-of-ros" aria-label="Permalink to &quot;How can I use a different version of ROS?&quot;">​</a></h4><p>This works with <a href="https://hub.docker.com/_/ros/" target="_blank" rel="noreferrer">any supported version of ROS</a>, just edit the top line of the Dockerfile. For example, if you want ROS Kinetic:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">FROM</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ros</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">kinetic</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ros</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">base</span></span></code></pre></div><h4 id="can-i-use-my-favourite-ide-editor-with-this" tabindex="-1">Can I use [my favourite IDE/editor] with this? <a class="header-anchor" href="#can-i-use-my-favourite-ide-editor-with-this" aria-label="Permalink to &quot;Can I use \\[my favourite IDE/editor] with this?&quot;">​</a></h4><p>Yup! The <code>catkin_ws</code> directory is mounted as a volume inside the container, so you can edit your code as usual, and it will be automatically synced with the container.</p><h4 id="where-is-my-catkin-ws-workspace-mounted-inside-the-container" tabindex="-1">Where is my <code>catkin_ws</code> workspace mounted inside the container? <a class="header-anchor" href="#where-is-my-catkin-ws-workspace-mounted-inside-the-container" aria-label="Permalink to &quot;Where is my `catkin_ws` workspace mounted inside the container?&quot;">​</a></h4><p>Inside the container, the <code>catkin_ws</code> folder will be mounted at root (<code>/catkin_ws</code>).</p><h4 id="how-do-i-install-additional-packages-dependencies-tools" tabindex="-1">How do I install additional packages / dependencies / tools? <a class="header-anchor" href="#how-do-i-install-additional-packages-dependencies-tools" aria-label="Permalink to &quot;How do I install additional packages / dependencies / tools?&quot;">​</a></h4><p>Add your dependencies to the RUN command in the <code>Dockerfile</code> (this example installs <code>tmux</code> and <code>ros-kinetic-serial</code> packages using apt, you can add any additional commands or packages you like).</p><h4 id="i-need-another-terminal-window-in-the-container" tabindex="-1">I need another terminal window in the container! <a class="header-anchor" href="#i-need-another-terminal-window-in-the-container" aria-label="Permalink to &quot;I need another terminal window in the container!&quot;">​</a></h4><p>I recommend <a href="https://robots.thoughtbot.com/a-tmux-crash-course" target="_blank" rel="noreferrer">tmux</a> as an easy way to manage multiple shells in ROS.</p><p>However, if you really want multiple terminal windows instead, you can open a new terminal window on your host computer and run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -it</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ros-docker-simple</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /bin/bash</span></span></code></pre></div><h4 id="i-want-to-run-a-different-command-on-container-startup" tabindex="-1">I want to run a different command on container startup! <a class="header-anchor" href="#i-want-to-run-a-different-command-on-container-startup" aria-label="Permalink to &quot;I want to run a different command on container startup!&quot;">​</a></h4><p>You can give your command as an argument to <code>script/run</code>, for example:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">script/run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> roslaunch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.launch</span></span></code></pre></div><h4 id="how-do-i-pass-a-device-e-g-serial-joystick-to-the-container" tabindex="-1">How do I pass a device (e.g. serial, joystick) to the container? <a class="header-anchor" href="#how-do-i-pass-a-device-e-g-serial-joystick-to-the-container" aria-label="Permalink to &quot;How do I pass a device (e.g. serial, joystick) to the container?&quot;">​</a></h4><p>Edit <code>script/run</code> and add the line <code>--device=/dev/ttyUSB0 \\</code> (changing the <code>/dev</code> path to match the path to your device).</p><h4 id="how-can-i-easily-coordinate-multiple-containers-and-have-them-talk-to-one-another" tabindex="-1">How can I easily coordinate multiple containers and have them talk to one another? <a class="header-anchor" href="#how-can-i-easily-coordinate-multiple-containers-and-have-them-talk-to-one-another" aria-label="Permalink to &quot;How can I easily coordinate multiple containers and have them talk to one another?&quot;">​</a></h4><p>The <code>docker-compose</code> tool is the standard way to run multiple containers together: <a href="https://docs.docker.com/compose/overview/" target="_blank" rel="noreferrer">https://docs.docker.com/compose/overview/</a></p><h4 id="running-the-scripts-gives-me-a-permission-denied-error" tabindex="-1">Running the scripts gives me a <code>permission denied</code> error! <a class="header-anchor" href="#running-the-scripts-gives-me-a-permission-denied-error" aria-label="Permalink to &quot;Running the scripts gives me a `permission denied` error!&quot;">​</a></h4><p>Is it this one?</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Got</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> permission</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> denied</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> while</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> trying</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> to</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> connect</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> to</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> the</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> daemon</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> socket</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> at</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> unix:///var/run/docker.sock:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Post</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://%2Fvar%2Frun%2Fdocker.sock/v1.26/containers/create:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dial</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> unix</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/run/docker.sock:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> connect:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> permission</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> denied.</span></span></code></pre></div><p>Reason: your user does not have privileges to run Docker. Put your user into the <code>docker</code> group or run with <code>sudo</code>.</p><h4 id="it-gives-me-a-ros-entrypoint-sh-line-6-no-such-file-or-directory-error" tabindex="-1">It gives me a <code>/ros_entrypoint.sh: line 6: (...): No such file or directory</code> error! <a class="header-anchor" href="#it-gives-me-a-ros-entrypoint-sh-line-6-no-such-file-or-directory-error" aria-label="Permalink to &quot;It gives me a `/ros_entrypoint.sh: line 6: (...): No such file or directory` error!&quot;">​</a></h4><p>Instead of giving it a command like this:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">script/run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;cd /tmp/ &amp;&amp; ls&quot;</span></span></code></pre></div><p>Try this:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">script/run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;cd /tmp/ &amp;&amp; ls&quot;</span></span></code></pre></div>',37)])])}const u=e(n,[["render",o]]);export{k as __pageData,u as default};
